// This script tests the time tracking dashboard implementation

const fs = require('fs');
const path = require('path');

// Test results storage
const testResults = {
  timestamp: new Date().toISOString(),
  tests: [],
  summary: {
    total: 0,
    passed: 0,
    failed: 0
  }
};

/**
 * Run a test and record the result
 * @param {string} name - Test name
 * @param {Function} testFn - Test function
 */
function runTest(name, testFn) {
  testResults.summary.total++;
  try {
    const result = testFn();
    if (result) {
      testResults.summary.passed++;
      testResults.tests.push({
        name,
        status: 'passed',
        message: 'Test passed successfully'
      });
      console.log(`✓ ${name}`);
    } else {
      testResults.summary.failed++;
      testResults.tests.push({
        name,
        status: 'failed',
        message: 'Test returned false'
      });
      console.log(`✗ ${name}`);
    }
  } catch (error) {
    testResults.summary.failed++;
    testResults.tests.push({
      name,
      status: 'failed',
      message: error.message
    });
    console.log(`✗ ${name}: ${error.message}`);
  }
}

// Test 1: Check if index.html exists and has required structure
runTest('index.html exists', () => {
  return fs.existsSync('index.html');
});

runTest('index.html has DOCTYPE', () => {
  const html = fs.readFileSync('index.html', 'utf8');
  return html.includes('<!DOCTYPE html>');
});

runTest('index.html has proper lang attribute', () => {
  const html = fs.readFileSync('index.html', 'utf8');
  return html.includes('lang="en"');
});

runTest('index.html has viewport meta tag', () => {
  const html = fs.readFileSync('index.html', 'utf8');
  return html.includes('viewport');
});

runTest('index.html links styles.css', () => {
  const html = fs.readFileSync('index.html', 'utf8');
  return html.includes('styles.css');
});

runTest('index.html links script.js', () => {
  const html = fs.readFileSync('index.html', 'utf8');
  return html.includes('script.js');
});

runTest('index.html has profile card section', () => {
  const html = fs.readFileSync('index.html', 'utf8');
  return html.includes('profile-card') || html.includes('profile');
});

runTest('index.html has time switcher', () => {
  const html = fs.readFileSync('index.html', 'utf8');
  return html.includes('time-switcher') || html.includes('switcher');
});

runTest('index.html has activities container', () => {
  const html = fs.readFileSync('index.html', 'utf8');
  return html.includes('activities') || html.includes('activities-grid');
});

runTest('index.html has Daily/Weekly/Monthly buttons', () => {
  const html = fs.readFileSync('index.html', 'utf8');
  return html.includes('Daily') && html.includes('Weekly') && html.includes('Monthly');
});

// Test 2: Check if styles.css exists and has required styles
runTest('styles.css exists', () => {
  return fs.existsSync('styles.css');
});

runTest('styles.css has CSS reset', () => {
  const css = fs.readFileSync('styles.css', 'utf8');
  return css.includes('box-sizing: border-box') || css.includes('* {');
});

runTest('styles.css has color variables', () => {
  const css = fs.readFileSync('styles.css', 'utf8');
  return css.includes('--navy-950') || css.includes('hsl(226');
});

runTest('styles.css has activity colors', () => {
  const css = fs.readFileSync('styles.css', 'utf8');
  return css.includes('--work-color') && css.includes('--play-color');
});

runTest('styles.css has Rubik font', () => {
  const css = fs.readFileSync('styles.css', 'utf8');
  return css.includes('Rubik') || css.includes('--font-family');
});

runTest('styles.css has responsive design', () => {
  const css = fs.readFileSync('styles.css', 'utf8');
  return css.includes('@media');
});

runTest('styles.css has grid layout', () => {
  const css = fs.readFileSync('styles.css', 'utf8');
  return css.includes('display: grid') || css.includes('grid-');
});

runTest('styles.css has hover states', () => {
  const css = fs.readFileSync('styles.css', 'utf8');
  return css.includes(':hover');
});

runTest('styles.css has focus states', () => {
  const css = fs.readFileSync('styles.css', 'utf8');
  return css.includes(':focus');
});

// Test 3: Check if script.js exists and has required functionality
runTest('script.js exists', () => {
  return fs.existsSync('script.js');
});

runTest('script.js loads data.json', () => {
  const js = fs.readFileSync('script.js', 'utf8');
  return js.includes('data.json') || js.includes('fetch');
});

runTest('script.js has time period switching', () => {
  const js = fs.readFileSync('script.js', 'utf8');
  return js.includes('daily') && js.includes('weekly') && js.includes('monthly');
});

runTest('script.js has previous labels', () => {
  const js = fs.readFileSync('script.js', 'utf8');
  return js.includes('Yesterday') && js.includes('Last Week') && js.includes('Last Month');
});

runTest('script.js renders activity cards', () => {
  const js = fs.readFileSync('script.js', 'utf8');
  return js.includes('activity-card') || js.includes('createActivityCard');
});

runTest('script.js has event listeners', () => {
  const js = fs.readFileSync('script.js', 'utf8');
  return js.includes('addEventListener');
});

// Test 4: Check if data.json exists and has correct structure
runTest('data.json exists', () => {
  return fs.existsSync('data.json');
});

runTest('data.json is valid JSON', () => {
  try {
    const data = JSON.parse(fs.readFileSync('data.json', 'utf8'));
    return Array.isArray(data);
  } catch {
    return false;
  }
});

runTest('data.json has 6 activities', () => {
  const data = JSON.parse(fs.readFileSync('data.json', 'utf8'));
  return data.length === 6;
});

runTest('data.json has Work activity', () => {
  const data = JSON.parse(fs.readFileSync('data.json', 'utf8'));
  return data.some(a => a.title === 'Work');
});

runTest('data.json has timeframes for each activity', () => {
  const data = JSON.parse(fs.readFileSync('data.json', 'utf8'));
  return data.every(a => a.timeframes && a.timeframes.daily && a.timeframes.weekly && a.timeframes.monthly);
});

runTest('data.json activities have current and previous values', () => {
  const data = JSON.parse(fs.readFileSync('data.json', 'utf8'));
  return data.every(a => 
    Object.values(a.timeframes).every(tf => 
      typeof tf.current === 'number' && typeof tf.previous === 'number'
    )
  );
});

// Test 5: Check file sizes are reasonable
runTest('index.html has reasonable size', () => {
  const stats = fs.statSync('index.html');
  return stats.size > 500 && stats.size < 10000;
});

runTest('styles.css has reasonable size', () => {
  const stats = fs.statSync('styles.css');
  return stats.size > 1000 && stats.size < 50000;
});

runTest('script.js has reasonable size', () => {
  const stats = fs.statSync('script.js');
  return stats.size > 500 && stats.size < 50000;
});

