{"content": "/* CSS Reset and Base Styles */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  /* Primary Colors */
  --purple-600: hsl(246, 80%, 60%);
  --orange-300: hsl(15, 100%, 70%);
  --blue-300: hsl(195, 74%, 62%);
  --pink-400: hsl(348, 100%, 68%);
  --green-400: hsl(145, 58%, 55%);
  --purple-700: hsl(264, 64%, 52%);
  --yellow-300: hsl(43, 84%, 65%);

  /* Neutral Colors */
  --navy-950: hsl(226, 43%, 10%);
  --navy-900: hsl(235, 46%, 20%);
  --purple-500: hsl(235, 45%, 61%);
  --navy-200: hsl(236, 100%, 87%);

  /* Activity Colors */
  --work-color: var(--orange-300);
  --play-color: var(--blue-300);
  --study-color: var(--pink-400);
  --exercise-color: var(--green-400);
  --social-color: var(--purple-700);
  --self-care-color: var(--yellow-300);

  /* Typography */
  --font-family: 'Rubik', sans-serif;
  --font-size-body: 18px;
  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
}

body {
  font-family: var(--font-family);
  background-color: var(--navy-950);
  color: white;
  min-height: 100vh;
  padding: 2rem;
}

/* Dashboard Container */
.dashboard-container {
  max-width: 1440px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: 1fr;
  gap: 2rem;
}

/* Profile Card */
.profile-card {
  background-color: var(--navy-900);
  border-radius: 16px;
  padding: 2rem;
  display: flex;
  flex-direction: column;
  gap: 2rem;
}

.profile-header {
  display: flex;
  align-items: center;
  gap: 1.5rem;
}

.profile-image {
  width: 56px;
  height: 56px;
  border-radius: 50%;
  border: 3px solid white;
  object-fit: cover;
}

.profile-info {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.profile-label {
  font-size: 1rem;
  font-weight: var(--font-weight-light);
  color: var(--navy-200);
}

.profile-name {
  font-size: 2rem;
  font-weight: var(--font-weight-regular);
}

/* Time Switcher */
.time-switcher {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
}

.switcher-btn {
  background: transparent;
  border: none;
  color: var(--navy-200);
  font-family: var(--font-family);
  font-size: 1rem;
  font-weight: var(--font-weight-regular);
  cursor: pointer;
  padding: 0.5rem 1rem;
  border-radius: 8px;
  transition: all 0.2s ease;
}

.switcher-btn:hover {
  color: white;
  background-color: rgba(255, 255, 255, 0.1);
}

.switcher-btn.active {
  color: white;
}

.switcher-btn.active::after {
  content: '';
  display: block;
  width: 100%;
  height: 4px;
  background-color: var(--purple-600);
  border-radius: 2px;
  margin-top: 0.25rem;
}

.switcher-btn:focus {
  outline: 2px solid var(--purple-600);
  outline-offset: 2px;
}

/* Activities Grid */
.activities-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 1.5rem;
}

/* Activity Card */
.activity-card {
  background-color: var(--navy-900);
  border-radius: 16px;
  overflow: hidden;
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.activity-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
}

.activity-card:focus-within {
  outline: 2px solid var(--purple-600);
  outline-offset: 2px;
}

.activity-card-header {
  height: 8px;
  width: 100%;
}

.activity-card-header.work {
  background-color: var(--work-color);
}

.activity-card-header.play {
  background-color: var(--play-color);
}

.activity-card-header.study {
  background-color: var(--study-color);
}

.activity-card-header.exercise {
  background-color: var(--exercise-color);
}

.activity-card-header.social {
  background-color: var(--social-color);
}

.activity-card-header.self-care {
  background-color: var(--self-care-color);
}

.activity-card-body {
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}

.activity-card-top {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 1rem;
}

.activity-title {
  font-size: 1.125rem;
  font-weight: var(--font-weight-regular);
}

.activity-menu-btn {
  background: transparent;
  border: none;
  color: white;
  font-size: 1.5rem;
  cursor: pointer;
  opacity: 0.5;
  transition: opacity 0.2s ease;
  line-height: 1;
}

.activity-menu-btn:hover,
.activity-menu-btn:focus {
  opacity: 1;
  outline: none;
}

.activity-time {
  font-size: 2.5rem;
  font-weight: var(--font-weight-light);
  line-height: 1.2;
}

.activity-time span {
  font-size: 1.125rem;
  font-weight: var(--font-weight-regular);
}

.activity-previous {
  font-size: 0.875rem;
  font-weight: var(--font-weight-light);
  color: var(--navy-200);
}

/* Attribution */
.attribution {
  text-align: center;
  margin-top: 3rem;
  font-size: 0.75rem;
  color: var(--navy-200);
}

.attribution a {
  color: var(--purple-500);
  text-decoration: none;
}

.attribution a:hover {
  text-decoration: underline;
}

/* Responsive Design - Desktop */
@media (min-width: 1024px) {
  body {
    padding: 3rem;
  }

  .dashboard-container {
    grid-template-columns: 280px 1fr;
    grid-template-areas:
      "profile activities"
      "profile activities";
  }

  .profile-card {
    grid-area: profile;
    height: fit-content;
    position: sticky;
    top: 3rem;
  }

  .profile-header {
    flex-direction: column;
    text-align: center;
  }

  .time-switcher {
    flex-direction: column;
    align-items: stretch;
  }

  .switcher-btn {
    text-align: center;
    padding: 0.75rem 1rem;
  }

  .switcher-btn.active::after {
    display: none;
  }

  .switcher-btn.active {
    background-color: var(--purple-600);
  }

  .activities-grid {
    grid-area: activities;
    grid-template-columns: repeat(3, 1fr);
    grid-template-rows: repeat(2, 1fr);
  }

  .activity-card {
    min-height: 180px;
  }
}

/* Responsive Design - Mobile */
@media (max-width: 375px) {
  body {
    padding: 1rem;
  }

  .profile-card {
    padding: 1.5rem;
  }

  .profile-name {
    font-size: 1.5rem;
  }

  .time-switcher {
    gap: 0.5rem;
  }

  .switcher-btn {
    font-size: 0.875rem;
    padding: 0.375rem 0.75rem;
  }

  .activity-card-body {
    padding: 1.25rem;
  }

  .activity-time {
    font-size: 2rem;
  }
}

/* Accessibility - Reduced Motion */
@media (prefers-reduced-motion: reduce) {
  * {
    transition: none !important;
    animation: none !important;
  }
}

/* Accessibility - High Contrast */
@media (prefers-contrast: high) {
  .switcher-btn.active {
    border: 2px solid white;
  }

  .activity-card {
    border: 1px solid var(--navy-200);
  }
}", "path": "styles.css"}

{"content": "// Time Tracking Dashboard - Main Script

// Activity color mapping for card headers
const activityColors = {
  'Work': 'work',
  'Play': 'play',
  'Study': 'study',
  'Exercise': 'exercise',
  'Social': 'social',
  'Self Care': 'self-care'
};

// Time period labels for previous time display
const previousLabels = {
  'daily': 'Yesterday',
  'weekly': 'Last Week',
  'monthly': 'Last Month'
};

// Current active time period
let currentPeriod = 'weekly';

// Dashboard data
let dashboardData = [];

/**
 * Format time value with appropriate suffix
 * @param {number} hours - Number of hours
 * @returns {string} Formatted time string
 */
function formatTime(hours) {
  if (hours === 1) {
    return '1hr';
  }
  return `${hours}hrs`;
}

/**
 * Get activity color class based on title
 * @param {string} title - Activity title
 * @returns {string} Color class name
 */
function getActivityColorClass(title) {
  return activityColors[title] || 'work';
}

/**
 * Create an activity card element
 * @param {Object} activity - Activity data object
 * @param {string} period - Current time period (daily/weekly/monthly)
 * @returns {HTMLElement} Activity card element
 */
function createActivityCard(activity, period) {
  const card = document.createElement('article');
  card.className = 'activity-card';
  card.setAttribute('data-activity', activity.title.toLowerCase().replace(' ', '-'));
  card.setAttribute('tabindex', '0');
  card.setAttribute('role', 'article');
  card.setAttribute('aria-label', `${activity.title} time tracking`);

  const timeframes = activity.timeframes[period];
  const colorClass = getActivityColorClass(activity.title);
  const previousLabel = previousLabels[period];

  card.innerHTML = `
    <div class="activity-card-header ${colorClass}" role="presentation"></div>
    <div class="activity-card-body">
      <div class="activity-card-top">
        <h2 class="activity-title">${activity.title}</h2>
        <button class="activity-menu-btn" aria-label="More options for ${activity.title}">
          <svg width="4" height="20" viewBox="0 0 4 20" fill="currentColor" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
            <circle cx="2" cy="2" r="2" fill="currentColor"/>
            <circle cx="2" cy="10" r="2" fill="currentColor"/>
            <circle cx="2" cy="18" r="2" fill="currentColor"/>
          </svg>
        </button>
      </div>
      <div class="activity-time" aria-live="polite">
        ${formatTime(timeframes.current)}<span></span>
      </div>
      <p class="activity-previous">${previousLabel} - ${formatTime(timeframes.previous)}</p>
    </div>
  `;

  return card;
}

/**
 * Render all activity cards
 * @param {string} period - Time period to display
 */
function renderActivities(period) {
  const container = document.getElementById('activities-container');
  container.innerHTML = '';

  dashboardData.forEach(activity => {
    const card = createActivityCard(activity, period);
    container.appendChild(card);
  });
}

/**
 * Update the active state of switcher buttons
 * @param {string} period - Active time period
 */
function updateSwitcherButtons(period) {
  const buttons = document.querySelectorAll('.switcher-btn');
  buttons.forEach(btn => {
    if (btn.dataset.period === period) {
      btn.classList.add('active');
      btn.setAttribute('aria-pressed', 'true');
    } else {
      btn.classList.remove('active');
      btn.setAttribute('aria-pressed', 'false');
    }
  });
}

/**
 * Handle time period switch
 * @param {string} period - New time period
 */
function switchTimePeriod(period) {
  currentPeriod = period;
  renderActivities(period);
  updateSwitcherButtons(period);
}

/**
 * Initialize switcher button event listeners
 */
function initSwitcherButtons() {
  const buttons = document.querySelectorAll('.switcher-btn');
  buttons.forEach(btn => {
    btn.addEventListener('click', () => {
      switchTimePeriod(btn.dataset.period);
    });

    btn.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        switchTimePeriod(btn.dataset.period);
      }
    });
  });
}

/**
 * Load data from JSON file
 * @returns {Promise<Array>} Dashboard data
 */
async function loadData() {
  try {
    const response = await fetch('data.json');
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    dashboardData = await response.json();
    return dashboardData;
  } catch (error) {
    console.error('Error loading data:', error);
    // Fallback data if fetch fails
    dashboardData = [
      {
        "title": "Work",
        "timeframes": {
          "daily": { "current": 5, "previous": 7 },
          "weekly": { "current": 32, "previous": 36 },
          "monthly": { "current": 103, "previous": 128 }
        }
      },
      {
        "title": "Play",
        "timeframes": {
          "daily": { "current": 1, "previous": 2 },
          "weekly": { "current": 10, "previous": 8 },
          "monthly": { "current": 23, "previous": 29 }
        }
      },
      {
        "title": "Study",
        "timeframes": {
          "daily": { "current": 0, "previous": 1 },
          "weekly": { "current": 4, "previous": 7 },
          "monthly": { "current": 13, "previous": 19 }
        }
      },
      {
        "title": "Exercise",
        "timeframes": {
          "daily": { "current": 1, "previous": 1 },
          "weekly": { "current": 4, "previous": 5 },
          "monthly": { "current": 11, "previous": 18 }
        }
      },
      {
        "title": "Social",
        "timeframes": {
          "daily": { "current": 1, "previous": 3 },
          "weekly": { "current": 5, "previous": 10 },
          "monthly": { "current": 21, "previous": 23 }
        }
      },
      {
        "title": "Self Care",
        "timeframes": {
          "daily": { "current": 0, "previous": 1 },
          "weekly": { "current": 2, "previous": 2 },
          "monthly": { "current": 7, "previous": 11 }
        }
      }
    ];
    return dashboardData;
  }
}

/**
 * Initialize the dashboard
 */
async function init() {
  await loadData();
  initSwitcherButtons();
  renderActivities(currentPeriod);
  updateSwitcherButtons(currentPeriod);

  console.log('Dashboard initialized successfully');
  console.log('Loaded', dashboardData.length, 'activities');
}

// Start the dashboard when DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}

// Export for testing purposes
if (typeof module !== 'undefined' && module.exports) {
  module.exports = {
    formatTime,
    getActivityColorClass,
    createActivityCard,
    switchTimePeriod,
    previousLabels,
    activityColors
  };
}", "path": "script.js"}

